const email_rec = $('Extract Data').item.json.recipient_email;
let channel_id = "";

// Add routing logic for your emails
// Just setting dummy channel IDs
channel_id = "YOUR_CHANNEL_ID";

$input.item.json.discord_channel = channel_id;
return $input.item;

for (let item of $input.all()) {

  // 1. SECURITY: If Gemini crashed
  if (item.json.error || item.error || !item.json.content) {
    item.json.intent_data = { 
        intent: "OBJECTION", 
        urgency: "IMMEDIATE", 
        explanation: "⚠️ AI crashed", 
        objection_type: null,
        draft: "Sorry, I couldn't generate a draft. Please reply manually."
    };
    continue;
  }

  // 2. Clean Gemini JSON (remove markdown tags)
  let rawText = item.json?.content?.parts?.[0]?.text || item.json.text || item.json.message?.content || "{}";
  let cleanText = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();

  try {
    item.json.intent_data = JSON.parse(cleanText);
  } catch (error) {
    // Security if AI misformatted its JSON
    item.json.intent_data = { 
      intent: "OBJECTION", 
      urgency: "IMMEDIATE", 
      explanation: "AI formatting error", 
      objection_type: null, 
      draft: "" 
    };
  }
}

return $input.all();

// 1. Extract PROSPECT email
const fromField = $input.item.json.from;
let email_exp = "";
if (fromField && fromField.value && fromField.value.length > 0) {
  email_exp = fromField.value[0].address;
} else if (typeof fromField === 'string') {
  const match = fromField.match(/<(.+)>/);
  email_exp = match ? match[1] : fromField;
}

// 2. Extract OUR email (The mailbox that received the message)
const toField = $input.item.json.to;
let email_rec = "";
if (toField && toField.value && toField.value.length > 0) {
  email_rec = toField.value[0].address;
} else if (typeof toField === 'string') {
  const match = toField.match(/<(.+)>/);
  email_rec = match ? match[1] : toField;
}

return { 
  json: { 
    sender_email: email_exp.toLowerCase().trim(),
    recipient_email: email_rec.toLowerCase().trim(),
    email_body: $input.item.json.text || $input.item.json.textPlain || $input.item.json.textHtml || "No text",
    message_id: $input.item.json.messageId,
    email_subject: $input.item.json.subject
  } 
};
